parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "business_unit_name": {
      "type": "string",
      "enum": [
        "AI & Automation",
        "Business Operations & Back-Office",
        "Digital Experience & Product Development",
        "Finance & Accounting",
        "Marketing & Brand",
        "Project Management & BI",
        "Sales & Customer Success",
        "System Integrations"
      ]
    },
    "new_scope": { "type": "string" },
    "new_keywords": {
      "type": "array",
      "items": { "type": "string" },
      "minItems": 1,
      "maxItems": 7
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    }
  },
  "required": ["business_unit_name", "new_scope", "new_keywords", "confidence"]
}

parameters.jsCode:
const src = $('Loop (1 a la vez)').item.json;
const out = $json.output || $json;
return {
  json: {
    proposal_id: src.id,
    upwork_id: src.upwork_id,
    job_title: src.job_title,
    status: src.status,
    keyword: src.keyword,
    bu_name: out.business_unit_name,
    new_scope: out.new_scope,
    new_keywords: out.new_keywords,
    confidence: out.confidence,
    would_skip: out.confidence < 0.7,
  },
};
